import{c as t,Q as s,j as a,m as i}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"ADR-024 — Mission URL sharing","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-024.md","filePath":"adr/ADR-024.md"}'),o={name:"adr/ADR-024.md"};function n(r,e,l,h,d,c){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-024-—-mission-url-sharing" tabindex="-1">ADR-024 — Mission URL sharing <a class="header-anchor" href="#adr-024-—-mission-url-sharing" aria-label="Permalink to &quot;ADR-024 — Mission URL sharing&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-29 Closes · RFC-004 (mission URL sharing) TA anchor · §components/router · §contracts/url-params</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-004 raised the question of how to surface mission state in URLs so a user can share a launch window or a specific mission&#39;s flight: <code>/fly?mission=curiosity</code>, <code>/missions?dest=MARS</code>, <code>/missions?dest=MOON&amp;status=ACTIVE</code>. The open questions were:</p><ol><li><strong>Param vocabulary.</strong> Which fields make it into the URL — just <code>mission</code>, or also <code>dest</code>, <code>status</code>, <code>vehicle</code>, <code>tof</code>, <code>dep_day</code>?</li><li><strong>State serialisation.</strong> Is the URL the source of truth, or a one-way display? If the user changes a filter, do we update the URL?</li><li><strong>Back-button behaviour.</strong> Should every filter toggle land in the back-button history?</li><li><strong>Default state.</strong> When <code>?mission</code> isn&#39;t present, what loads on <code>/fly</code>?</li></ol><p>Closure was originally scheduled for the Slice 4 gate; we close it here in 4a-6 alongside the e2e tests that validate the contract end-to-end.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="param-vocabulary-locked" tabindex="-1">Param vocabulary (locked) <a class="header-anchor" href="#param-vocabulary-locked" aria-label="Permalink to &quot;Param vocabulary (locked)&quot;">​</a></h3><p>Only the parameters that materially change what the user sees ship in the URL.</p><table tabindex="0"><thead><tr><th>Route</th><th>Param</th><th>Values</th><th>Default</th><th>Source of truth</th></tr></thead><tbody><tr><td><code>/fly</code></td><td><code>mission</code></td><td>mission id (e.g. <code>curiosity</code>, <code>apollo11</code>, omitted)</td><td>omitted → ORRERY-1</td><td>URL</td></tr><tr><td><code>/missions</code></td><td><code>dest</code></td><td><code>MARS</code> | <code>MOON</code> | omitted</td><td>omitted → ALL</td><td>URL</td></tr><tr><td><code>/missions</code></td><td><code>status</code></td><td><code>ACTIVE</code> | <code>FLOWN</code> | <code>PLANNED</code> | omitted</td><td>omitted → ALL</td><td>URL</td></tr></tbody></table><p>Vehicle, transit time, and other porkchop-cell parameters intentionally do <strong>not</strong> ship in the URL. They&#39;re surfaced by the porkchop interaction itself — sharing a <code>/plan</code> URL takes the recipient to the same plot, not the same selected cell. RFC-004&#39;s trade-off discussion concluded that &quot;share an exact cell&quot; is a v2 feature once the porkchop UX is more mature; for now the colour pattern is the educational surface.</p><h3 id="state-serialisation-—-url-is-the-source-of-truth-on-entry" tabindex="-1">State serialisation — URL is the source of truth on entry <a class="header-anchor" href="#state-serialisation-—-url-is-the-source-of-truth-on-entry" aria-label="Permalink to &quot;State serialisation — URL is the source of truth on entry&quot;">​</a></h3><p>Each route reads <code>$page.url.searchParams</code> in <code>onMount</code> (and on subsequent URL changes via <code>$effect</code>) and applies the params to component state. Filter / mission changes write back to the URL via <code>goto(target, { replaceState: true })</code> so the back-button history isn&#39;t littered with every toggle.</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// missions/+page.svelte</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> pushFiltersToUrl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> params</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> URLSearchParams</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (destFilter </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ALL&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) params.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;dest&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, destFilter);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (statusFilter </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ALL&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) params.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">set</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;status&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, statusFilter);</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  goto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">base</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}/missions?${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, { replaceState: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, keepFocus: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, noScroll: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>replaceState</code> was chosen deliberately. Without it, three filter clicks produce three back-button entries; the user&#39;s mental model is &quot;one screen, refining&quot; so we collapse the history.</p><h3 id="back-button-behaviour-—-page-level-not-filter-level" tabindex="-1">Back-button behaviour — page-level, not filter-level <a class="header-anchor" href="#back-button-behaviour-—-page-level-not-filter-level" aria-label="Permalink to &quot;Back-button behaviour — page-level, not filter-level&quot;">​</a></h3><p>Browser back returns the user to the previous <em>page</em>, not the previous <em>filter state</em>. This matches the prevailing convention for SaaS apps and tested as more intuitive in the prototype than per-filter history.</p><h3 id="default-state" tabindex="-1">Default state <a class="header-anchor" href="#default-state" aria-label="Permalink to &quot;Default state&quot;">​</a></h3><p><code>/fly</code> with no <code>?mission=</code> param shows the canonical ORRERY-1 free-return scenario. We chose this over &quot;last visited mission&quot; (would require localStorage which CLAUDE.md forbids) and &quot;first mission alphabetically&quot; (arbitrary and confusing). A user landing on <code>/fly</code> cold gets the educational scenario the rest of the app references.</p><p>If <code>?mission=id</code> is present but the mission doesn&#39;t exist (typo, deleted overlay), a top-banner alert surfaces the failure and the screen falls back to ORRERY-1. The banner is <code>role=&quot;alert&quot;</code> so screen readers announce the fallback.</p><h3 id="cross-route-navigation-fly-this-mission" tabindex="-1">Cross-route navigation (FLY THIS MISSION) <a class="header-anchor" href="#cross-route-navigation-fly-this-mission" aria-label="Permalink to &quot;Cross-route navigation (FLY THIS MISSION)&quot;">​</a></h3><p>The MissionPanel&#39;s FLY CTA constructs the URL via <code>goto(</code>${base}/fly?mission=${id}<code>)</code> rather than passing state through Svelte stores or session storage. This makes the deep link self-contained — copy the resulting URL into a chat or email and it works.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>URL-as-source-of-truth on entry + replaceState on update gives us:</p><ul><li><strong>Shareability</strong>: any state the user cares about lives in the URL they can copy.</li><li><strong>Back-button correctness</strong>: page-level history without per-toggle noise.</li><li><strong>No localStorage</strong>: complies with CLAUDE.md&#39;s prohibition; works fully offline; nothing to migrate when the user clears site data.</li></ul><p>The vocabulary stays small. Adding params is a one-line schema change in the consuming route — but every new param is a maintenance cost (URL-readers, URL-writers, e2e coverage), so we explicitly defer porkchop-cell parameters until there&#39;s a user case for them.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>State in localStorage</strong> — rejected per CLAUDE.md.</li><li><strong>Hash routing for state</strong> — rejected: ADR-013 already locked History API routing.</li><li><strong>Push every filter toggle to history</strong> — rejected: clutters the back-button stack with no user value (tested informally on the prototype).</li><li><strong>Server-side state via /api endpoints</strong> — rejected: ADR-014 locks GitHub Pages static deploy; no backend.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: deep-link sharing works for the two highest-value cases (a mission, a destination filter); back-button matches user expectation; state is debuggable at a glance because it&#39;s in the address bar.</p><p>Negative: porkchop-cell sharing is unimplemented. If a user wants to share &quot;this exact launch window for ∆v=6.2 km/s on day 412&quot;, they currently can&#39;t — they have to share <code>/plan</code> and verbally describe the cell. Tracked as a v2 issue.</p><h2 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h2><p>Closing evidence: 7 of the 20 e2e tests added in 4a-6 (<code>tests/e2e/fly.spec.ts</code>) and 6 of 6 in 4a-2 (<code>tests/e2e/missions.spec.ts</code>) cover the URL contract end-to-end. Specifically:</p><ul><li><code>/missions?dest=MARS</code> pre-applies the filter on cold load</li><li>MARS / MOON filter toggles update the URL with <code>replaceState</code></li><li><code>/fly?mission=curiosity</code> populates the identity HUD with Curiosity data</li><li><code>/fly?mission=apollo11</code> loads the Moon-dest fallback</li><li><code>/fly?mission=does-not-exist</code> surfaces the load-failed banner</li><li>Mission library → click card → click FLY navigates to <code>/fly?mission=id</code> and the fly screen loads the correct mission</li></ul>',34)])])}const k=t(o,[["render",n]]);export{u as __pageData,k as default};
